<!-- Settings Page Index View -->\n<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <title>Settings</title>\n</head>\n<body>\n<h1>User Settings</h1>\n\n<?php if (isset($errors)): ?>\n    <div style='color: red; border: 1px solid red; padding: 10px;'>\n        Errors:<br><?php echo implode('<br>', array_values($errors)); ?>\n    </div>\n<?php endif; ?><br>\n\n<form action="/settings" method="POST">\n    <label for="theme">Theme:</label>\n    <select name="theme" id="theme">\n        <option value="light" <?php echo (isset($settings) && $settings['theme'] == 'light') ? 'selected' : ''; ?>>Light</option>\n        <option value="dark" <?php echo (isset($settings) && $settings['theme'] == 'dark') ? 'selected' : ''; ?>>Dark</option>\n    </select><br><br>\n\n    <label for="notifications">Email Notifications:</label>\n    <input type="checkbox" name="notifications" id="notifications" <?php echo (isset($settings) && $settings['notifications']) ? 'checked' : ''; ?>><br><br>\n\n    <button type="submit">Save Settings</button>\n</form>\n</body>\n</html>
